import sys

def binary_search(arr, low, high, x):
    if high >= low:
        mid = (low + high) // 2
        if arr[mid] == x:
            return mid
        elif arr[mid] > x:
            return binary_search(arr, low, mid - 1, x)
        else:
            return binary_search(arr, mid + 1, high, x)
    return -1

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        arr = [int(next(it)) for _ in range(N)]
        X = int(next(it))
        out_lines.append(str(binary_search(arr, 0, N - 1, X)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

